import { useContext, useEffect } from "react"
import { useLocation, useNavigate } from "react-router-dom"
import SpinCustom from "src/components/SpinCustom"
import { StoreContext } from "src/contexts"
import { encode_data } from "src/lib/encoder"
import STORAGE, { setStorage } from "src/lib/storage"
import ROUTER from "src/router/ROUTER"
import AuthService from "src/services/AuthService"

const LoginGG = () => {
  const location = useLocation()
  const ID = location?.search?.slice(4)
  const navigate = useNavigate()
  const { loginStore, routerBeforeStore } = useContext(StoreContext)
  const { setIsLoginContext } = loginStore
  const { routerBeforeLogin, setRouterBeforeLogin } = routerBeforeStore
  useEffect(() => {
    if (ID) getToken()
  }, [ID])

  const getToken = async () => {
    try {
      const res = await AuthService.callbackGG({ ID })
      if (res?.isError) return
      let router = ROUTER.HOME
      setStorage(STORAGE.TOKEN, res?.Object?.Token)
      setStorage(STORAGE.USER_INFO, res?.Object)
      navigate(router)
      setRouterBeforeLogin(undefined)
      const data_hash = encode_data(STORAGE.TOKEN)
      setIsLoginContext(data_hash)
      setRouterBeforeLogin(undefined)
      // navigate(ROUTER.TONG_QUAN)
    } finally {
      console.log("getToken")
    }
  }
  return <SpinCustom spinning />
}

export default LoginGG
